endpoint.response:
Download `text/csv` (Content-Disposition attachment, filename `{domain}-import-template.csv`)
con UNA riga header = gli id colonna dichiarati dalla ImportDefinition, es.
business-functions: `name,type`;
companies: `denomination,vat_number,country,region,province,city,street,postal_code`;
operational-sites: `country,region,province,city,street,postal_code`;
roles: `name,permissions` (permissions = lista pipe-delimited `|`);
users: `email,type,first_name,last_name,company_name,locale,roles` (roles = lista pipe-delimited `|`; nessuna colonna password).

{ success, message, data: { import_run: {
  id:number, resource:string, status:'validating',
  original_filename:string, total_rows:0, valid_rows:0, invalid_rows:0,
  imported_rows:null, has_error_report:false, created_at:string
} } }

{ success, message, data: {
  import_run: {
    id:number, resource:string,
    status:'validating'|'awaiting_confirmation'|'processing'|'completed'|'failed',
    original_filename:string,
    total_rows:number, valid_rows:number, invalid_rows:number,
    imported_rows:number|null,          
    has_error_report:boolean,
    created_at:string
  },
  preview: {                            
    columns: string[],                  
    valid_sample: Array<Record>,   
    invalid_sample: Array<{ row_number:number, values:Record, errors:string[] }>  
  } | null
} }
